const input = $('Execute Workflow Trigger').first().json;
const config = $('Get Config').first().json;
const tier = config.tiers[input.tier] || config.tiers.starter;

const clientName = String(input.clientName || input.company || '').trim() || 'Client';
const company = String(input.company || input.clientName || '').trim();

return [{
  json: {
    clientName,
    company,
    industry: input.industry || '',
    tier: input.tier || 'starter',
    tierName: tier.name,
    monthlyPrice: tier.monthlyPrice,
    setupFee: tier.setupFee,
    startDate: input.startDate || new Date().toISOString().split('T')[0],
    dealValue: input.dealValue || 0,
    painPoints: input.painPoints || '',
    ownerPhone: config.owner.phone,
    ownerEmail: config.owner.email,
    contactEmail: input.contactEmail || '',
    contactFirstName: input.contactFirstName || '',
    driveFolderId: input.driveFolderId || '',
    config
  }
}];

const MAX = 7;
const d = $('Extract Input Data').first().json;
const prompts = $('Prep Section Prompts').all().slice(0, MAX);
const generated = $input.all().slice(0, MAX);

const sectionBody = (section) => {
  const j = section.json || {};
  if (j.data && typeof j.data.text === 'string' && j.data.text.trim()) return j.data.text;
  if (typeof j.text === 'string' && j.text.trim()) return j.text;
  if (j.success === false && j.error) {
    const safe = String(j.error).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
    return `<section><p style=\"color:#b00020;\"><strong>Section failed:</strong> ${safe}</p></section>`;
  }
  return '<section><p style=\"color:#b00020;\">No content was returned for this section.</p></section>';
};

const fileNameFor = (sectionTitle) => {
  const t = String(sectionTitle || 'Section').replace(/[\/:*?\"<>|]+/g, ' ').replace(/\s+/g, ' ').trim() || 'Section';
  return `IntraWeb — ${d.clientName} — ${t}.pdf`;
};

const styles = `<style>
  @import url('https://fonts.googleapis.com/css2?family=DM+Sans:wght@400;500;700&display=swap');
  body { font-family: 'DM Sans', Arial, sans-serif; color: #333; line-height: 1.6; max-width: 800px; margin: 0 auto; padding: 40px; }
  h1 { color: #1a1f2e; border-bottom: 3px solid #3d8b8b; padding-bottom: 10px; }
  h2 { color: #1a1f2e; margin-top: 40px; }
  h3 { color: #3d8b8b; }
  a { color: #3d8b8b; }
  .header { background: #1a1f2e; color: white; padding: 40px; margin: -40px -40px 40px -40px; text-align: center; }
  .header h1 { color: #3d8b8b; border: none; }
  .header p { color: #ccc; }
  table { width: 100%; border-collapse: collapse; margin: 20px 0; }
  th, td { padding: 10px; text-align: left; border-bottom: 1px solid #eee; }
  th { background: #f5f5f5; color: #1a1f2e; }
</style>`;

const n = Math.min(MAX, prompts.length, generated.length);
const out = [];
for (let i = 0; i < n; i++) {
  const sectionName = (prompts[i] && prompts[i].json && prompts[i].json.sectionName) ? prompts[i].json.sectionName : `Section ${i + 1}`;
  const body = generated[i] ? sectionBody(generated[i]) : '<section><p style=\"color:#b00020;\">Missing generated output for this section.</p></section>';
  const html = `<!DOCTYPE html><html><head>${styles}</head><body><div class=\"header\"><h1>IntraWeb Technologies</h1><p>${sectionName.replace(/&/g, '&amp;').replace(/</g, '&lt;')}</p><p>Onboarding — ${String(d.clientName).replace(/&/g, '&amp;').replace(/</g, '&lt;')}</p></div>${body}</body></html>`;
  out.push({ json: { html, fileName: fileNameFor(sectionName), sectionName } });
}
return out;

const MAX = 7;
const items = $input.all().slice(0, MAX);
const out = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const j = item.json || {};
  const fileName = (j.data && j.data.fileName) || j.fileName || 'onboarding-section.pdf';
  const inlineBinary = item.binary && item.binary.data && item.binary.data.data;
  let b64 = typeof inlineBinary === 'string' && inlineBinary !== 'filesystem-v2' ? inlineBinary : '';

  if (!b64 && item.binary && item.binary.data) {
    const pdfBuffer = await this.helpers.getBinaryDataBuffer(i, 'data');
    b64 = pdfBuffer.toString('base64');
  }

  if (!b64 && j.data && typeof j.data.pdfBase64 === 'string') {
    b64 = j.data.pdfBase64;
  }

  if (!b64) {
    throw new Error(
      'Attach PDF Binary: missing usable PDF bytes for ' +
        fileName +
        '. ' +
        JSON.stringify({ success: j.success, error: j.error }).slice(0, 400),
    );
  }

  out.push({
    json: j,
    binary: {
      data: {
        data: b64,
        mimeType: (j.data && j.data.mimeType) || 'application/pdf',
        fileName,
        fileExtension: 'pdf'
      },
    },
  });
}

return out;

const MAX = 7;
const d = $('Extract Input Data').first().json;
const uploads = $('Upload file').all().slice(0, MAX);
const items = uploads.map((u) => {
  const id = u.json.id;
  const nm = u.json.name || u.json.title || 'Document';
  return { id, name: nm, href: id ? `https://drive.google.com/file/d/${id}/view` : '' };
}).filter((x) => x.href);

const listHtml = items.length
  ? `<ul style=\"margin:16px 0;padding-left:20px;\">${items.map((x) => `<li style=\"margin:8px 0;\"><a href=\"${x.href}\">${String(x.name).replace(/&/g, '&amp;').replace(/</g, '&lt;')}</a></li>`).join('')}</ul>`
  : '<p><em>Documents could not be linked automatically — check your Google Drive folder.</em></p>';

return [{
  json: {
    to: d.contactEmail,
    subject: 'Your IntraWeb onboarding documents — seven guides to get started',
    html: `<p>Hi ${d.contactFirstName || 'there'},</p><p>Your onboarding package is ready as <strong>separate PDFs</strong> (welcome letter, access guide, what we're building, timeline, how we work together, billing, and FAQ).</p>${listHtml}<p>Take a few minutes to review them, and let me know if you have any questions.</p><p>— John<br/>${d.config.owner.companyName}</p>`,
    workflowName: 'SYS 04 — Client Onboarding Docs Generator'
  }
}];

const d = $('Extract Input Data').first().json;

return [{
  json: {
    to: d.contactEmail,
    body: `Hi ${d.contactFirstName || 'there'}, just checking you received your onboarding package — check your inbox and let us know if you have any questions. — John`,
    workflowName: 'SYS 04 — Client Onboarding Docs Generator'
  }
}];

return [{
  json: {
    workflowName: 'SYS 04 — Client Onboarding Docs Generator',
    contactName: $('Extract Input Data').first().json.clientName,
    phone: '', eventType: 'onboarding_started', status: 'success',
    notes: 'Onboarding package generated and sent'
  }
}];

// Labor only (matches sticky). The 24h Wait node is clock time, not labor.
const manualByTask = [
  { task: 'Pull CONFIG + normalize client / tier / Drive context', min: 12 },
  { task: 'Draft 7 onboarding sections (research, tone, client specifics)', min: 95 },
  { task: 'Assemble per-section HTML + filenames + QA pass', min: 26 },
  { task: 'Generate 7 PDFs + upload each to client Drive + verify links', min: 20 },
  { task: 'Compose and send onboarding package email', min: 10 },
  { task: 'Prep + send 24h follow-up SMS', min: 6 },
  { task: 'Log doc delivery to ops sheet', min: 4 }
];
const humanByTask = [
  { task: 'Skim AI sections for wrong tier / wrong client details', min: 10 },
  { task: 'Optional: tweak email or SMS wording', min: 5 }
];
const manualLaborMinutes = manualByTask.reduce((s, t) => s + t.min, 0);
const residualHumanMinutes = humanByTask.reduce((s, t) => s + t.min, 0);
const minutesSaved = manualLaborMinutes - residualHumanMinutes;

const base = $input.first().json;
return [{
  json: {
    ...base,
    minutesSaved,
    timeSavedBreakdown: {
      manualLaborMinutes,
      residualHumanMinutes,
      manualByTask,
      humanByTask
    }
  }
}];
